package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;

import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetEscapeCharacter_Default() {
        CSVFormat format = CSVFormat.DEFAULT;
        Character escapeChar = format.getEscapeCharacter();
        assertNull(escapeChar, "Default CSVFormat escapeCharacter should be null");
    }

    @Test
    void testGetEscapeCharacter_WithEscapeChar() {
        CSVFormat format = CSVFormat.DEFAULT.withEscape('\\');
        Character escapeChar = format.getEscapeCharacter();
        assertNotNull(escapeChar, "EscapeCharacter should not be null after withEscape");
        assertEquals(Character.valueOf('\\'), escapeChar, "EscapeCharacter should be backslash");
    }

    @Test
    void testGetEscapeCharacter_WithEscapeChar_Null() {
        CSVFormat format = CSVFormat.DEFAULT.withEscape((Character) null);
        Character escapeChar = format.getEscapeCharacter();
        assertNull(escapeChar, "EscapeCharacter should be null when set to null explicitly");
    }

    @Test
    void testGetEscapeCharacter_InformixUnload() {
        CSVFormat format = CSVFormat.INFORMIX_UNLOAD;
        Character escapeChar = format.getEscapeCharacter();
        assertNotNull(escapeChar, "INFORMIX_UNLOAD escapeCharacter should not be null");
        assertEquals(Character.valueOf('\\'), escapeChar, "INFORMIX_UNLOAD escapeCharacter should be backslash");
    }

    @Test
    void testGetEscapeCharacter_MySQL() {
        CSVFormat format = CSVFormat.MYSQL;
        Character escapeChar = format.getEscapeCharacter();
        assertNotNull(escapeChar, "MYSQL escapeCharacter should not be null");
        assertEquals(Character.valueOf('\\'), escapeChar, "MYSQL escapeCharacter should be backslash");
    }

    @Test
    void testGetEscapeCharacter_PostgreSQLCSV() {
        CSVFormat format = CSVFormat.POSTGRESQL_CSV;
        Character escapeChar = format.getEscapeCharacter();
        assertNotNull(escapeChar, "POSTGRESQL_CSV escapeCharacter should not be null");
        assertEquals(Character.valueOf('"'), escapeChar, "POSTGRESQL_CSV escapeCharacter should be double quote");
    }

    @Test
    void testGetEscapeCharacter_PostgreSQLText() {
        CSVFormat format = CSVFormat.POSTGRESQL_TEXT;
        Character escapeChar = format.getEscapeCharacter();
        assertNotNull(escapeChar, "POSTGRESQL_TEXT escapeCharacter should not be null");
        assertEquals(Character.valueOf('"'), escapeChar, "POSTGRESQL_TEXT escapeCharacter should be double quote");
    }

    @Test
    void testGetEscapeCharacter_TDF() {
        CSVFormat format = CSVFormat.TDF;
        Character escapeChar = format.getEscapeCharacter();
        assertNull(escapeChar, "TDF escapeCharacter should be null");
    }
}
